import Image from 'next/image';
import { ArrowRight } from 'lucide-react';
import { getContent } from '@/lib/content';

function Media({ url, type, alt, className }: { url: string; type?: string; alt: string; className?: string }) {
  if (type === 'video') return <video className={className} src={url} autoPlay muted loop playsInline />;
  return <Image className={className} src={url} alt={alt} fill sizes="(max-width: 900px) 100vw, 60vw" />;
}

export default async function Home() {
  const content = await getContent();
  return (
    <main>
      <header className="topbar">
        <a className="brand" href="#top">{content.brand}</a>
        <nav>{content.nav.map((item) => <a key={item} href={`#${item.toLowerCase()}`}>{item}</a>)}</nav>
        <a className="darkButton" href="mailto:hello@seenmotions.com">GET IN TOUCH</a>
      </header>

      <section id="top" className="hero">
        {content.hero.backgroundVideoUrl ? <video className="heroVideo" src={content.hero.backgroundVideoUrl} autoPlay muted loop playsInline /> : null}
        <div className="split left" />
        <div className="split right" />
        <div className="logoCard"><Image src={content.hero.logoUrl} alt="Seen Motions mark" width={128} height={128} /></div>
        <div className="heroCopy">
          <h1>{content.hero.title.split('\n').map((line) => <span key={line}>{line}</span>)}</h1>
          <p>{content.hero.subtitle}</p>
          <a className="goldButton" href="mailto:hello@seenmotions.com">{content.hero.button}<ArrowRight size={20} /></a>
        </div>
      </section>

      <section id="work" className="works">
        <div className="sectionHead"><h2>{content.works.title}</h2><span>{content.works.eyebrow}</span></div>
        <div className="workGrid">
          {content.works.items.map((item, index) => (
            <article key={`${item.title}-${index}`} className={index === 0 ? 'workLarge' : 'workSmall'}>
              <div className="mediaWrap"><Media url={item.mediaUrl} type={item.type} alt={item.title} /></div>
              <div className="caption"><span>{item.title}</span><span>{item.year}</span></div>
            </article>
          ))}
        </div>
        <button className="lightButton">{content.works.button}<ArrowRight size={20} /></button>
      </section>

      <section id="services" className="services">
        <h2>SERVICES</h2>
        <div className="serviceGrid">
          {content.services.map((service) => (
            <article key={service.number}>
              <span className="number">{service.number}</span>
              <h3>{service.title.split('\n').map((line) => <span key={line}>{line}</span>)}</h3>
              <p>{service.body}</p>
            </article>
          ))}
        </div>
      </section>

      <section id="studio" className="vision">
        <h2>{content.vision.title}</h2>
        <p>{content.vision.body}</p>
      </section>

      <footer>
        <strong>{content.brand}</strong>
        <div className="footerLinks">{content.footer.links.map((link) => <a key={link}>{link}</a>)}</div>
        <p>{content.footer.copyright}</p>
      </footer>
    </main>
  );
}
